// Domain Classification and Content Processing
const items = $input.all();
const processedItems = [];

// Domain classification keywords
const domainKeywords = {
  finance: ['stock', 'market', 'trading', 'economy', 'financial', 'investment', 'crypto', 'currency', 'fund', 'bond', 'earnings', 'bloomberg'],
  sports: ['game', 'match', 'player', 'team', 'score', 'season', 'championship', 'tournament', 'league', 'coach', 'espn'],
  technology: ['technology', 'software', 'ai', 'startup', 'app', 'digital', 'innovation', 'coding', 'tech', 'data', 'apple', 'google']
};

// Style parameter variations
const styleTemplates = {
  finance: {
    tones: ['professional', 'analytical', 'authoritative'],
    structures: ['analysis', 'news', 'market-update'],
    lengths: ['medium', 'long'],
    perspectives: ['third-person', 'expert-analysis']
  },
  technology: {
    tones: ['analytical', 'engaging', 'authoritative'],
    structures: ['tutorial', 'analysis', 'news'],
    lengths: ['medium', 'long'],
    perspectives: ['expert-analysis', 'third-person']
  },
  general: {
    tones: ['conversational', 'professional'],
    structures: ['news', 'analysis'],
    lengths: ['short', 'medium'],
    perspectives: ['third-person']
  }
};

for (const item of items) {
  const title = item.json.title || '';
  const description = item.json.description || item.json.contentSnippet || '';
  const content = (title + ' ' + description).toLowerCase();

  // Classify domain
  let domain = 'general';
  for (const [domainName, keywords] of Object.entries(domainKeywords)) {
    if (keywords.some(keyword => content.includes(keyword))) {
      domain = domainName;
      break;
    }
  }

  // Generate random style parameters
  const styleConfig = styleTemplates[domain];
  const randomStyle = {
    tone: styleConfig.tones[Math.floor(Math.random() * styleConfig.tones.length)],
    structure: styleConfig.structures[Math.floor(Math.random() * styleConfig.structures.length)],
    length: styleConfig.lengths[Math.floor(Math.random() * styleConfig.lengths.length)],
    perspective: styleConfig.perspectives[Math.floor(Math.random() * styleConfig.perspectives.length)]
  };

  // Generate content ID
  const contentId = `ai_${domain}_${Date.now()}_${Math.random().toString(36).substr(2, 6)}`;

  console.log(`Processing: ${title} - Domain: ${domain}`);

  processedItems.push({
    json: {
      content_id: contentId,
      domain: domain,
      source_title: title,
      source_description: description,
      source_url: item.json.link,
      pub_date: item.json.pubDate || item.json.isoDate,
      style_parameters: randomStyle,
      processing_timestamp: new Date().toISOString()
    }
  });
}

console.log(`Processed ${processedItems.length} items for AI generation`);
return processedItems;

// Advanced Prompt Engineering for Claude
const item = $input.first();
const data = item.json;

// Domain-specific prompt templates
const promptTemplates = {
  finance: `You are a professional financial analyst writing for investors.

Source Material:
Title: {{source_title}}
Description: {{source_description}}

Instructions:
- Write a {{length}} {{structure}} article with a {{tone}} tone
- Use {{perspective}} perspective
- Target professional finance audience
- Include market analysis and investment implications
- Word count: {{target_words}} words

Write the complete article now:`,

  technology: `You are a technology expert writing for a tech-savvy audience.

Source Material:
Title: {{source_title}}
Description: {{source_description}}

Instructions:
- Write a {{length}} {{structure}} article with a {{tone}} tone
- Use {{perspective}} perspective
- Target technology professionals
- Include industry implications and trends
- Word count: {{target_words}} words

Write the complete article now:`,

  general: `You are a professional content writer.

Source Material:
Title: {{source_title}}
Description: {{source_description}}

Instructions:
- Write a {{length}} {{structure}} article with a {{tone}} tone
- Use {{perspective}} perspective
- Target general audience
- Provide valuable insights
- Word count: {{target_words}} words

Write the complete article now:`
};

// Word count mapping
const wordCounts = {
  short: 400,
  medium: 800,
  long: 1200
};

// Get template and replace placeholders
const template = promptTemplates[data.domain] || promptTemplates.general;
const targetWords = wordCounts[data.style_parameters.length] || 800;

const finalPrompt = template
  .replace(/{{source_title}}/g, data.source_title)
  .replace(/{{source_description}}/g, data.source_description)
  .replace(/{{length}}/g, data.style_parameters.length)
  .replace(/{{structure}}/g, data.style_parameters.structure)
  .replace(/{{tone}}/g, data.style_parameters.tone)
  .replace(/{{perspective}}/g, data.style_parameters.perspective)
  .replace(/{{target_words}}/g, targetWords);

console.log(`Generated prompt for ${data.content_id} - Domain: ${data.domain}`);

return [{
  json: {
    ...data,
    ai_prompt: finalPrompt,
    target_word_count: targetWords,
    prompt_version: '2.0'
  }
}];

// Content Quality Analysis
const items = $input.all();
const processedItems = [];

for (const item of items) {
  const generatedContent = item.json.response || item.json.content || item.json.text || 'Content generation failed';
  const originalData = $('Prompt Engineer').first().json;

  // Simple quality metrics
  const wordCount = generatedContent.split(/\s+/).length;
  const targetCount = originalData.target_word_count || 800;
  const lengthScore = Math.max(0, 100 - Math.abs(wordCount - targetCount) / targetCount * 100);

  // Basic content quality checks
  const hasTitle = generatedContent.toLowerCase().includes(originalData.source_title.toLowerCase().split(' ')[0]);
  const hasSubstantiveContent = wordCount > 200;
  const hasStructure = generatedContent.includes('\n') || generatedContent.length > 500;

  const qualityScore = Math.round((lengthScore + (hasTitle ? 20 : 0) + (hasSubstantiveContent ? 30 : 0) + (hasStructure ? 10 : 0)) / 1.6);

  console.log(`Quality analysis for ${originalData.content_id}: ${qualityScore}/100 (${wordCount} words)`);

  processedItems.push({
    json: {
      ...originalData,
      generated_content: generatedContent,
      word_count: wordCount,
      quality_score: qualityScore,
      generation_timestamp: new Date().toISOString(),
      status: qualityScore >= 70 ? 'approved' : 'needs_review'
    }
  });
}

return processedItems;
